text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트가 통과하는 경우 금요일 15:00 KST를 공개 릴리스 목표 시점으로 한다."
      },
      {
        "topic": "packageName mismatch 대응",
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토로 진행한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "거부됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "note": "내부 스트레치 골일 뿐이며 최종 공개 릴리스 결정은 아니다."
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 절차 검토",
        "note": "목요일까지 가능하면 검토하자는 의견은 있었으나 담당자는 지정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로",
        "impact": "릴리스 지연 가능"
      },
      {
        "risk": "README 설치 절차가 오래된 상태일 가능성",
        "impact": "릴리스 노트가 사용자에게 오해를 줄 가능성"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 골을 언급해야 하는가?",
        "status": "미결정"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로를 점검한다.",
      "due": "미정",
      "status": "선행 결과 대기",
      "source_certainty": "확정"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 목요일까지 가능하면 검토한다.",
      "due": "목요일 가능하면",
      "status": "담당자 미배정",
      "source_certainty": "부분 확정"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 이후 Minjun의 스모크 테스트 결과를 확인한다.",
      "스모크 통과 여부에 따라 금요일 15:00 KST 공개 릴리스 목표 유지 가능성을 다시 확인한다.",
      "스모크 결과 공유 후 Hara의 tarball 경로 점검 결과를 확인한다.",
      "금요일 12:00 KST까지 Doyun의 failure triage note 작성 여부를 확인한다.",
      "README 설치 절차 검토 담당자 지정 필요 여부를 확인한다.",
      "최종 릴리스 승인 권한자를 확정해야 한다.",
      "릴리스 노트에 수요일 내부 스트레치 골을 언급할지 결정해야 한다."
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "지정되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "인라인 공개용 합성 픽스처에 없는 사실은 추가하지 않는다.",
    "확정 결정과 제안, 스트레치 골, 리스크, 미해결 질문을 구분한다.",
    "고객, 예산, 보안, 장애, 법무 관련 사실을 만들어내지 않는다.",
    "담당자와 마감일은 명시된 경우에만 확정으로 기록한다.",
    "수요일 일정은 내부 스트레치 골로만 기록하고 공개 릴리스 확정으로 승격하지 않는다."
  ]
}
